#include<bits/stdc++.h>
using namespace std;
int a[1001],dp[25010];
int main()
{
    int t;
    scanf("%d",&t);
    while(t--)
    {
        int n;
        scanf("%d",&n);
        memset(dp,0,sizeof(dp));
        for(int i=1;i<=n;i++)
        {
            scanf("%d",&a[i]);
        }
        int ans=n;
        sort(a+1,a+1+n);
        dp[0]=1;
        for(int i=1;i<=n;i++)
        {
            if(dp[a[i]])
            {
                ans--;
            }
            for(int j=a[i];j<=a[n];j++)
            {
                dp[j]=dp[j]|dp[j-a[i]];
            }
        }
        printf("%d\n",ans);
    }
    return 0;
}
